// Bestimmt pro Lead, ob JETZT eine Follow-up-Stage fällig ist (T3/T7/T14).
// Nie mehrfach dieselbe Stage senden; nach Stage 3 wird der Lead auf 'done' gesetzt.
const STAGE_DAYS = { 1: 3, 2: 7, 3: 14 };
const STAGE_LABEL = { 1: 'T3', 2: 'T7', 3: 'T14' };
const rows = ($input.first().json.rows || []);
const now = new Date();
const out = [];
for (const row of rows) {
  const data = row.data || {};
  if (data.status === 'done') continue;
  const offerSentAt = data.offer_sent_at ? new Date(data.offer_sent_at) : null;
  if (!offerSentAt || isNaN(offerSentAt.getTime())) continue;
  const currentStage = Number(data.followup_stage || 0);
  const nextStage = currentStage + 1;
  const dueDays = STAGE_DAYS[nextStage];
  if (!dueDays) continue; // schon alle 3 Stufen gesendet
  const dueAt = new Date(offerSentAt.getTime() + dueDays * 24 * 60 * 60 * 1000);
  if (now < dueAt) continue; // noch nicht fällig
  out.push({
    json: {
      row_id: row.id,
      lead_id: data.lead_id || row.id,
      stage: nextStage,
      stage_label: STAGE_LABEL[nextStage],
      offer_sent_at: data.offer_sent_at,
      lead_kontext: data.lead_kontext || '',
      bisherige_mails: data.bisherige_mails || '',
      send_target: data.email || data.send_target || '',
      is_last_stage: nextStage === 3,
    },
  });
}
return out;
